// ── Parse Claude Response + Save Static Data + Save Pending ──
const claudeResponse = $input.first().json;
const prevData = $('Prepare Claude Request (JP)').first().json;

let resultText = claudeResponse.content?.[0]?.text || '{}';

const jsonMatch = resultText.match(/```json\s*([\s\S]*?)\s*```/);
if (jsonMatch) resultText = jsonMatch[1];

let parsed;
try {
  parsed = JSON.parse(resultText);
} catch (e) {
  parsed = {
    reply: resultText,
    needs_human_review: false,
    alert_reason: null,
    alert_note: null,
    stage: 'other',
  };
}

const staticData = $getWorkflowStaticData('global');
staticData[prevData.subscriber_id] = prevData.messages.slice(-20);

staticData['pending_' + prevData.subscriber_id] = {
  reply: parsed.reply || '',
  subscriber_name: prevData.subscriber_name,
  new_message: prevData.new_message,
  stage: parsed.stage || 'other',
  needs_human_review: parsed.needs_human_review || false,
  alert_reason: parsed.alert_reason || null,
  alert_note: parsed.alert_note || null,
  created_at: new Date().toISOString(),
};

// Auto-transition detection
let autoTransition = null;
if (parsed.alert_reason === 'posting_completed') {
  autoTransition = { from: 'sample_delivered', to: 'posted', trigger: 'dm_keyword' };
} else if (parsed.alert_reason === 'ad_code_shared') {
  autoTransition = { from: 'posted', to: 'ad_code_received', trigger: 'dm_keyword' };
}

return [{
  json: {
    ...parsed,
    subscriber_id: prevData.subscriber_id,
    subscriber_name: prevData.subscriber_name,
    new_message: prevData.new_message,
    auto_transition: autoTransition,
  }
}];

