const staticData = $getWorkflowStaticData('global');
const query = $input.first().json.query || {};
const subscriberId = (query.id || '').toString().trim();

if (!subscriberId) throw new Error('id query parameter is required');

const pendingKey = 'pending_' + subscriberId;
const pending = staticData[pendingKey];

if (!pending) throw new Error('No pending reply for subscriber: ' + subscriberId);

return [{
  json: {
    subscriber_id: subscriberId,
    reply: pending.reply,
    subscriber_name: pending.subscriber_name,
    stage: pending.stage,
    pending_key: pendingKey,
  }
}];

const staticData = $getWorkflowStaticData('global');
const pendingData = $('Read Pending (GET)').first().json;
const subscriberId = pendingData.subscriber_id;
const pendingKey = pendingData.pending_key;

const history = staticData[subscriberId] || [];
history.push({ role: 'assistant', content: pendingData.reply || '' });
staticData[subscriberId] = history.slice(-20);

delete staticData[pendingKey];

return [{ json: { success: true, subscriber_id: subscriberId, subscriber_name: pendingData.subscriber_name } }];

