const body = $input.first().json.body || $input.first().json;
const subscriberId = (body.id || '').toString().trim();
const newReply = (body.reply || '').toString().trim();

if (!subscriberId || !newReply) throw new Error('Missing id or reply');

return [{
  json: {
    subscriber_id: subscriberId,
    reply: newReply,
    pending_key: 'pending_' + subscriberId,
  }
}];

const staticData = $getWorkflowStaticData('global');
const editData = $('Process Edit Submit').first().json;
const subscriberId = editData.subscriber_id;
const pendingKey = editData.pending_key;

const history = staticData[subscriberId] || [];
history.push({ role: 'assistant', content: editData.reply || '' });
staticData[subscriberId] = history.slice(-20);

delete staticData[pendingKey];

return [{ json: { success: true, subscriber_id: subscriberId } }];

// ── Auto Transition: update PG status based on DM keyword detection ──
const data = $input.first().json;
const at = data.auto_transition;

if (!at) return [{ json: { skipped: true, reason: 'no_auto_transition' } }];

// Call JP Pipeline API to update status
const username = data.subscriber_name || '';
const cleanHandle = username.startsWith('@') ? username : '@' + username;

return [{
  json: {
    should_update: true,
    username: cleanHandle,
    new_status: at.to,
    from_status: at.from,
    trigger: at.trigger,
    subscriber_id: data.subscriber_id,
  }
}];
